HERO_DESCRIPTIONS = {
    "Abaddon": "Абаддон — лорд Фосфора, который не даёт своим союзникам умереть. Его щит поглощает урон, а тёмное исцеление обращает боль в силу. Когда враги пытаются добить его команду, ультимейт Абаддона превращает все негативные эффекты в восстановление здоровья, делая его настоящим ангелом-хранителем.",
    "Alchemist": "Безумный химик, который варит крепкие зелья и щедро делится ими с командой. Алхимик быстро фармит золото и предметы, а его ультимейт превращает его в огромного неуязвимого берсерка, разбрасывающего врагов гранатами.",
    "Ancient Apparition": "Ледяной дух, который поражает врагов на расстоянии. Его заклинания замедляют и наносят урон с течением времени, а ультимейт Ancient Apparition не даёт противникам лечиться, гарантируя смерть самым живучим героям.",
    "Anti Mage": "Беспощадный охотник на магов, который сжигает ману врагов и наносит огромный урон в ближнем бою. Его способность к телепортации и быстрому перемещению позволяет ему появляться в самых неожиданных местах, а ультимейт карает противников за потраченную ману.",
    "Arc Warden": "Тёмный двойник, который может создавать свою точную копию. Оба героя используют предметы и заклинания одновременно, что делает Arc Warden опасным как в защите, так и в нападении. Его ультимейт призывает вторую сущность, удваивая мощь.",
    "Axe": "Безумный берсерк с огромным топором, который провоцирует врагов атаковать его. Чем больше противников вокруг, тем чаще срабатывает его пассивная способность. Ультимейт Axe мгновенно убивает цель с низким здоровьем, наводя ужас на вражеских героев.",
    "Bane": "Кошмарный демон, который вселяет страх и отнимает силы. Он усыпляет врагов и высасывает из них здоровье, а его ультимейт полностью парализует одного противника, оставляя его беззащитным перед союзниками.",
    "Batrider": "Всадник на огненной летучей мыши, который мастерски затягивает врагов в свою команду. Его способности поджигают и замедляют противников, а ультимейт Batrider — мощный огненный коктейль, который уничтожает всех на своём пути.",
    "Beastmaster": "Повелитель диких зверей, который призывает свирепых существ и использует метательные топоры. Его ультимейт — оглушающий рёв, который пронзает врагов и даёт команде преимущество в любой схватке.",
    "Bloodseeker": "Кровавый охотник, который чует раненых врагов и получает невероятную скорость. Его ультимейт накладывает на цель кровавый ритуал, наносящий урон при каждом движении — противник вынужден замирать или умирать.",
    "Bounty Hunter": "Хитрый охотник за головами, который становится невидимым и наносит критический удар из тени. Его ультимейт помечает врага, за убийство которого вся команда получает дополнительное золото, делая Bounty Hunter идеальным разведчиком.",
    "Brewmaster": "Мастер пивоварения, который разделяется на три стихии — огонь, ветер и землю. Каждая стихия обладает своими способностями, а ультимейт Brewmaster создаёт огненную бурю, уничтожая врагов в радиусе действия.",
    "Bristleback": "Грязная свинья, которая совсем не против подставить врагам спину. Уменьшая весь урон, который ему наносят сзади и сбоку, он безрассудно бросается в бой и обдаёт врагов смертоносными иглами и замедляющими соплями.",
    "Broodmother": "Мать всех пауков, которая плетёт липкую паутину и призывает полчища паучков. Бродмазер быстрее всех передвигается в своей паутине, а её укусы отравляют врагов, делая её королевой ночных лесов.",
    "Centaur Warrunner": "Могучий кентавр, который бьёт врагов собственным телом и оглушает их мощным ударом. Его ультимейт наносит глобальный урон всем врагам на карте и замедляет их, идеально подходит для начала сражения.",
    "Chaos Knight": "Рыцарь хаоса, который сеет разрушение своими иллюзиями и ударами. Он может создать множество копий себя, а его ультимейт призывает ещё одну мощную иллюзию, что делает его настоящим кошмаром для вражеских строений.",
    "Chen": "Святой, который подчиняет нейтральных крипов и лечит союзников. Его ультимейт — божественная защита, которая мгновенно исцеляет всех союзников и делает их неуязвимыми на короткое время.",
    "Clinkz": "Скелет-лучник, который невидимо подкрадывается к врагам и обрушивает на них град стрел. Его ультимейт сжигает здоровье противника огнём, превращая Clinkz в идеального убийцу одиночных целей.",
    "Clockwerk": "Безумный часовщик, который загоняет врагов в железную ловушку и запускает ракеты. Его ультимейт — глобальный ракетный удар, который глушит всех врагов в выбранной зоне, нарушая их планы.",
    "Crystal Maiden": "Ледяная дева, которая замедляет и замораживает врагов. Её ультимейт создаёт огромную зону холода, наносящую урон по площади, — идеальное оружие для командных сражений.",
    "Dark Seer": "Тёмный провидец, который создаёт иллюзии врагов и ускоряет союзников. Его ультимейт — стена иллюзий, которая копирует всех проходящих сквозь неё противников, переворачивая битву в вашу пользу.",
    "Dark Willow": "Загадочная фея, которая играет с врагами, оглушая и страшив их. Её ультимейт — огромный магический взрыв, который уничтожает всех, кто оказался в зоне поражения.",
    "Dawnbreaker": "Воительница света, которая призывает метеоры и исцеляет союзников. Её ультимейт — прыжок в центр битвы, который наносит урон и лечит всех в радиусе, делая её незаменимой в гуще событий.",
    "Dazzle": "Мудрый священник, который лечит союзников и усиливает их защиту, а также ослабляет врагов. Его ультимейт — благословение, которое увеличивает броню всех членов команды на длительное время.",
    "Death Prophet": "Пророчица смерти, которая высасывает здоровье врагов и призывает рой призрачных духов. Её ультимейт — танец смерти, в котором духи наносят огромный урон всем вокруг.",
    "Disruptor": "Разрушитель, который отправляет врагов в прошлое и накрывает их зоной молний. Его ультимейт — статическое поле, которое задерживает всех противников в радиусе, давая команде время на расправу.",
    "Doom": "Повелитель ада, который накладывает проклятие, запрещающее использовать способности. Его ультимейт — двойное проклятие, наносящее урон с течением времени и лишающее врага возможности сопротивляться.",
    "Dragon Knight": "Рыцарь-дракон, который может превращаться в дракона, получая мощное дыхание и улучшенные способности. Его ультимейт — огненная форма, которая делает его почти неуязвимым и смертоносным.",
    "Drow Ranger": "Меткая лучница, которая наносит колоссальный урон на расстоянии и замедляет врагов. Её ультимейт — пассивное увеличение урона, которое делает её одной из сильнейших стрелков в игре.",
    "Earth Spirit": "Дух земли, который катит камни и оглушает врагов, а также может перемещать союзников. Его ультимейт — магнитное поле, которое притягивает и наносит урон всем вокруг.",
    "Earthshaker": "Землетряс, который создаёт трещины и оглушает врагов мощными ударами. Его ультимейт — глобальное землетрясение, которое оглушает всех на карте на несколько секунд.",
    "Elder Titan": "Древний титан, который разделяет души противников и наносит урон, проходящий сквозь них. Его ультимейт — удар раскола, который наносит сокрушительный урон по площади.",
    "Ember Spirit": "Огненный дух, который прыгает по полю боя и оставляет за собой огненные частицы. Его ультимейт — серия быстрых атак, которые сжигают врагов дотла.",
    "Enchantress": "Очаровательница, которая подчиняет нейтральных крипов и лечит союзников. Её ультимейт — урон от расстояния — чем ближе враг, тем больше она его бьёт.",
    "Enigma": "Загадочное существо из пустоты, которое призывает идолов и создаёт чёрную дыру. Его ультимейт — чёрная дыра, которая притягивает всех врагов в центр, не давая им сбежать.",
    "Faceless Void": "Безликий, который управляет временем, останавливая его вокруг врагов. Его ультимейт — сфера времени, в которой все противники замирают, а он сам наносит критические удары.",
    "Grimstroke": "Мрачный художник, который рисует портреты врагов и накладывает на них проклятия. Его ультимейт — души, которые атакуют всех противников в радиусе, удваивая эффекты его заклинаний.",
    "Gyrocopter": "Вертолётчик, который стреляет ракетами и бомбами, а также умело маневрирует в небе. Его ультимейт — глобальная ракетная атака, наносящая урон всем врагам на карте.",
    "Hoodwink": "Маленький зверёк с арбалетом, который ловит врагов в сети и стреляет сквозь деревья. Её ультимейт — мощный снаряд, который пробивает всё на своём пути и оглушает цель.",
    "Huskar": "Дикарь, который жертвует своим здоровьем, чтобы наносить сокрушительные удары копьём. Его ультимейт — бросок копья, который замедляет врага и наносит урон в зависимости от недостающего здоровья.",
    "Invoker": "Великий маг, который комбинирует три стихии для создания более десятка заклинаний. Его ультимейт — катаклизм, уничтожающий всё на своём пути, — идеально подходит для опытных игроков.",
    "Io": "Светящаяся сфера, которая лечит союзников и привязывает их к себе. Её ультимейт — телепортация союзника в любую точку карты, что позволяет неожиданно атаковать или спасать.",
    "Jakiro": "Двуглавый дракон, который дышит льдом и огнём, замедляя и сжигая врагов. Его ультимейт — ледяная буря, которая наносит огромный урон по площади.",
    "Juggernaut": "Воин с мечом, который лечит себя и наносит удары в конусе. Его ультимейт — омни-слэш, в котором он прыгает по врагам и наносит им множество ударов, оставаясь неуязвимым.",
    "Keeper of the Light": "Хранитель света, который восстанавливает ману союзников и ослепляет врагов. Его ультимейт — световой луч, который наносит огромный урон и оглушает противников.",
    "Kez": "Новый герой 2026 года — мастер посоха, который может менять стиль боя в зависимости от ситуации. Его способности всё ещё изучаются, но он уже показывает себя как гибкий боец на линии.",
    "Kunkka": "Адмирал, который призывает корабль и наносит урон по площади. Его ультимейт — глобальная волна, которая сбивает всех врагов на линии, давая команде преимущество.",
    "Legion Commander": "Командир, которая вызывает врага на дуэль. Победитель дуэли получает дополнительную атаку навсегда, что делает её опасной в поздней игре.",
    "Leshrac": "Повелитель молний, который создаёт зоны урона и восстанавливает здоровье. Его ультимейт — молнии, которые бьют всех врагов в радиусе, не давая им спрятаться.",
    "Lich": "Лич, который жертвует крипов ради маны и наносит урон врагам. Его ультимейт — морозный взрыв, который перелетает между врагами, замедляя и убивая их.",
    "Lifestealer": "Паразит, который вселяется в тела врагов и высасывает их здоровье. Его ультимейт — контроль над вражеским героем, что позволяет переломить ход битвы.",
    "Lina": "Огненная волшебница, которая наносит магический урон и разгоняет себя. Её ультимейт — мощный огненный столб, который испепеляет любого врага.",
    "Lion": "Демонический маг, который оглушает и высасывает ману. Его ультимейт — огромный взрыв, который уничтожает одного врага, нанося ему колоссальный урон.",
    "Lone Druid": "Одиночный друид, который призывает свирепого медведя. У него два героя — он сам и его питомец, что делает его уникальным для игры на нескольких фронтах.",
    "Luna": "Лунная всадница, которая стреляет лунными лучами и увеличивает урон союзников. Её ультимейт — падающие с неба лучи, которые наносят урон всем врагам в радиусе.",
    "Lycan": "Волк-оборотень, который призывает стаю волков и становится невидимым. Его ультимейт — превращение в гигантского волка, который быстро бегает и сильно кусается.",
    "Magnus": "Магнус, который сбивает врагов в кучу и наносит им урон. Его ультимейт — объединение врагов в одной точке, что идеально для комбо с союзниками.",
    "Marci": "Марси — помощница, которая наносит быстрые удары и подкидывает врагов в воздух. Её ультимейт — прыжок с нанесением урона, который заставляет врагов разлетаться.",
    "Mars": "Бог войны, который создаёт стену копий и наносит урон. Его ультимейт — арена, в которой враги заперты, и он может бить их без помех.",
    "Medusa": "Горгона, которая превращает врагов в камень и неуязвима к магии. Её ультимейт — каменный взгляд, который замедляет всех врагов, делая их лёгкой мишенью.",
    "Meepo": "Геомант, который создаёт своих клонов. Все клоны получают опыт и золото, что позволяет ему быстро развиваться, но требует идеального контроля.",
    "Mirana": "Лунная принцесса, которая стреляет стрелой с огромной дистанции и становится невидимой. Её ультимейт — звёздный дождь, который наносит урон всем врагам в области.",
    "Monkey King": "Король обезьян, который лазает по деревьям и создаёт иллюзии. Его ультимейт — большой удар с земли, который наносит огромный урон и подбрасывает врагов.",
    "Morphling": "Морф, который меняет свою форму (сила/ловкость) и создаёт копию врага. Его ультимейт — перевоплощение в другого героя, что даёт ему доступ к его способностям.",
    "Muerta": "Мёртвая женщина-стрелок, которая стреляет призраками, игнорирующими защиту. Её ультимейт — двойной выстрел, который оглушает и наносит урон сразу двум целям.",
    "Naga Siren": "Сирена, которая поёт и усыпляет врагов, а также создаёт иллюзии. Её ультимейт — песня, которая заставляет всех врагов спать, давая команде время перегруппироваться.",
    "Nature's Prophet": "Пророк природы, который телепортируется по карте и призывает деревья. Его ультимейт — глобальный урон по всем врагам, который наносит урон независимо от их местоположения.",
    "Necrophos": "Некрофос, который накладывает проклятие и лечится от убийств. Его ультимейт — проклятие, которое убивает врага при низком здоровье, не давая ему спастись.",
    "Night Stalker": "Ночной охотник, который становится сильнее ночью. Его ультимейт — призыв ночи, которая даёт ему скорость и урон, делая его опасным в тёмное время суток.",
    "Nyx Assassin": "Ныкс, который становится невидимым и наносит критический урон из тени. Его ультимейт — шоковая волна, которая наносит урон и оглушает врагов вокруг.",
    "Ogre Magi": "Огр-маг, который атакует и может использовать способности дважды благодаря мультикасту. Его ультимейт — улучшенный мультикаст, который делает его случайным, но очень мощным.",
    "Omniknight": "Паладин, который исцеляет и защищает от магии, а также делает союзников неуязвимыми. Его ультимейт — глобальное исцеление и защита всей команды.",
    "Oracle": "Оракул, который предсказывает судьбу и может лечить или наносить урон по своему выбору. Его ультимейт — задержка урона, которая может спасти союзника от смерти.",
    "Outworld Destroyer": "Разрушитель миров, который сжигает ману врагов и наносит урон от интеллекта. Его ультимейт — сфера энергии, которая поражает всех врагов в радиусе.",
    "Pangolier": "Панголин, который стреляет из панциря и катится по земле, сбивая врагов. Его ультимейт — бросок панциря, который оглушает и наносит урон всем на пути.",
    "Phantom Assassin": "Призрачный убийца, которая наносит критические удары и уклоняется от атак. Её ультимейт — крит, который может мгновенно уничтожить врага.",
    "Phantom Lancer": "Призрачный копейщик, который создаёт множество иллюзий, сбивая врагов с толку. Его ультимейт — размножение, которое делает его практически неуловимым.",
    "Phoenix": "Феникс, который жертвует собой, чтобы возродиться с полным здоровьем. Его ультимейт — солнечный взрыв, который наносит урон и оглушает всех врагов в радиусе.",
    "Primal Beast": "Дикий зверь, который бьёт землю и наносит урон по площади. Его ультимейт — ярость, которая увеличивает его атаки и делает его почти неубиваемым.",
    "Puck": "Ледяной эльф, который уворачивается и наносит магический урон. Его ультимейт — сфера, которая заманивает врагов и наносит им урон, если они пытаются сбежать.",
    "Pudge": "Мясник, который ловит врагов крюком и ест их, восстанавливая здоровье. Его ультимейт — насыщение, которое делает его толстым и трудным для убийства.",
    "Pugna": "Гроза башен, которая создаёт башни и наносит урон врагам. Его ультимейт — взрыв жизни, который лечит союзников и наносит урон врагам одновременно.",
    "Queen of Pain": "Королева боли, которая телепортируется и наносит магический урон. Её ультимейт — ультимативное заклинание, которое поражает всех врагов вокруг неё.",
    "Razor": "Электрический воин, который крадёт урон у врагов и наносит им ответный удар. Его ультимейт — гроза, которая наносит урон всем врагам в радиусе.",
    "Riki": "Ниндзя, который становится невидимым и наносит урон со спины. Его ультимейт — удар сзади, который наносит дополнительный урон, если атаковать сзади.",
    "Ringmaster": "Новый герой 2026 года — мастер выступлений, пока его способности держатся в секрете. Ожидается, что он будет управлять толпой и создавать хаос.",
    "Rubick": "Вор заклинаний, который может украсть и использовать способности врагов. Его ультимейт — кража, которая позволяет ему использовать любую способность против её владельца.",
    "Sand King": "Король пустыни, который создаёт землетрясения и прячется в песке. Его ультимейт — эпицентр, который наносит огромный урон всем врагам в радиусе.",
    "Shadow Demon": "Демон теней, который создаёт иллюзии и портит врагов, замедляя их. Его ультимейт — разрыв, который наносит урон и замедляет врагов.",
    "Shadow Fiend": "Теневой дьявол, который собирает души и наносит урон по площади. Его ультимейт — требование душ, которое наносит колоссальный урон всем врагам вокруг.",
    "Shadow Shaman": "Шаман теней, который связывает и превращает врагов, а также призывает тотемы. Его ультимейт — тотемы, которые атакуют врагов и наносят огромный урон.",
    "Silencer": "Молчальник, который крадёт интеллект и не даёт врагам использовать способности. Его ультимейт — глобальное молчание, которое запрещает врагам применять заклинания на всей карте.",
    "Skywrath Mage": "Маг неба, который наносит магический урон и ускоряет союзников. Его ультимейт — мистраль, который наносит урон и замедляет врагов.",
    "Slardar": "Морской зверь, который уменьшает броню и оглушает врагов. Его ультимейт — амплификация урона, которая делает врага уязвимым для атак.",
    "Slark": "Рыболюд, который крадёт характеристики и становится невидимым. Его ультимейт — уклонение, которое делает его неуязвимым для атак на короткое время.",
    "Snapfire": "Бабушка с пушкой, которая стреляет и лечит союзников. Её ультимейт — огненный шар, который наносит урон всем врагам на пути.",
    "Sniper": "Снайпер, который стреляет издалека и наносит критический урон. Его ультимейт — снайперский выстрел, который наносит огромный урон одной цели.",
    "Spectre": "Призрак, который наносит урон всем врагам и телепортируется к цели. Её ультимейт — разрушение, которое создаёт иллюзию у каждой цели и наносит ей урон.",
    "Spirit Breaker": "Дух-разрушитель, который таранит врагов и оглушает их. Его ультимейт — мощный удар, который наносит урон и оглушает врага на длительное время.",
    "Storm Spirit": "Дух бури, который летает по полю и наносит магический урон. Его ультимейт — электрический шар, который наносит урон всем врагам на пути.",
    "Sven": "Воин, который оглушает и увеличивает свою силу, становясь гигантом. Его ультимейт — сверхсила, которая даёт ему огромный урон и сопротивление.",
    "Techies": "Инженеры, которые ставят мины и ловушки по всей карте. Их ультимейт — мощный взрыв, который уничтожает всех врагов в радиусе.",
    "Templar Assassin": "Ассасин из храма, которая пси-лезвиями режет врагов и становится невидимой. Её ультимейт — скрытность, которая делает её невидимой на короткое время.",
    "Terrorblade": "Демон, который создаёт иллюзии и меняется местами с врагами. Его ультимейт — метаморфоза, которая превращает его в мощного стрелка.",
    "Tidehunter": "Морской охотник, который оглушает всех врагов в радиусе мощным ударом. Его ультимейт — рейд, который наносит урон и оглушает всех вокруг.",
    "Timbersaw": "Лесоруб в машине, который рубит деревья и наносит урон. Его ультимейт — цепная реакция, которая наносит урон всем врагам в радиусе.",
    "Tinker": "Инженер, который восстанавливает способности и телепортируется по карте. Его ультимейт — перезарядка, которая позволяет ему использовать все способности снова.",
    "Tiny": "Каменный гигант, который кидает камни и увеличивается в размере. Его ультимейт — размер, который делает его больше, сильнее и медленнее.",
    "Treant Protector": "Древень, который лечит и становится невидимым в лесу. Его ультимейт — рост, который восстанавливает здоровье союзникам по всей карте.",
    "Troll Warlord": "Вождь троллей, который меняет оружие и ускоряет союзников. Его ультимейт — ярость, которая даёт ему огромную скорость атаки.",
    "Tusk": "Борец с кулаками, который создаёт снежные стены и бьёт врагов. Его ультимейт — удар, который наносит огромный урон и отбрасывает врага.",
    "Underlord": "Повелитель подземелья, который телепортирует союзников и наносит урон. Его ультимейт — тёмный портал, который открывает проход для всей команды.",
    "Undying": "Бессмертный, который воскрешает и крадёт силу у врагов. Его ультимейт — икона, которая воскрешает его после смерти.",
    "Ursa": "Медведь, который наносит огромный урон за несколько ударов, становясь опасным для любого героя. Его ультимейт — ярость, которая увеличивает урон от каждого удара.",
    "Vengeful Spirit": "Дух мести, который меняется местами с врагом и наносит урон. Её ультимейт — обмен, который может спасти союзника или убить врага.",
    "Venomancer": "Ядовитый маг, который отравляет и замедляет врагов. Его ультимейт — ядовитый взрыв, который наносит урон всем врагам в радиусе.",
    "Viper": "Змей, который замедляет и наносит урон с течением времени. Его ультимейт — яд, который делает врага медленным и уязвимым.",
    "Visage": "Некромант, который призывает горгулий и крадёт броню. Его ультимейт — каменная форма, которая делает его невосприимчивым к урону.",
    "Void Spirit": "Дух пустоты, который телепортируется и наносит урон врагам. Его ультимейт — удар, который наносит урон и замедляет врагов.",
    "Warlock": "Чернокнижник, который призывает голема и лечит союзников. Его ультимейт — хаос, который призывает огромного голема, сеющего разрушение.",
    "Weaver": "Ткач, который уменьшает броню и уклоняется от атак. Его ультимейт — путешествие во времени, которое возвращает его в прошлое.",
    "Windranger": "Стрелок, который стреляет снарядами и привязывает врагов к деревьям. Её ультимейт — фокус, который позволяет ей стрелять с огромной скоростью.",
    "Winter Wyvern": "Ледяной дракон, который лечит и замораживает врагов. Её ультимейт — ледяной удар, который наносит урон и замедляет всех врагов.",
    "Witch Doctor": "Шаман, который лечит и наносит урон, а также танцует в бою. Его ультимейт — танцы смерти, которые наносят урон всем врагам в радиусе.",
    "Wraith King": "Король-призрак, который воскрешается после смерти и оглушает врагов. Его ультимейт — воскрешение, которое позволяет ему вернуться к жизни.",
    "Zeus": "Бог грома, который наносит глобальный урон и молнии. Его ультимейт — кара, которая поражает всех врагов на карте, не давая им спрятаться."
}

def get_hero_description(name):
    """Возвращает объёмное описание героя по имени."""
    return HERO_DESCRIPTIONS.get(name, "Один из героев Dota 2. Изучите его способности и роль в команде.")

def get_hero_image_name(hero_name):
    """Возвращает имя файла для изображения героя (с учётом исключений)."""
    formatted = HERO_IMAGE_OVERRIDES.get(hero_name)
    if not formatted:
        formatted = hero_name.lower().replace(" ", "_").replace("-", "_").replace(".", "").replace(",", "")
    return formatted